import React, { useState } from 'react';
import { Box, Paper, Typography } from '@mui/material';
import { AddPhotoAlternate as AddPhotoIcon } from '@mui/icons-material';
import { motion } from 'framer-motion';

const MotionPaper = motion(Paper);

const PhotoBookPage = ({ format, photos, onPhotoAdd, onPhotoRemove }) => {
    const [isEditorOpen, setIsEditorOpen] = useState(false);
    const [selectedPhoto, setSelectedPhoto] = useState(null);

    // Вычисляем размеры страницы на основе формата
    const getPageDimensions = () => {
        const baseWidth = format.size === '20×20' ? 400 : format.size === '30×30' ? 500 : 600;
        const [width, height] = format.size.split('×').map(dim => parseInt(dim));
        const ratio = height / width;
        return {
            width: baseWidth,
            height: baseWidth * ratio
        };
    };

    const handleDragOver = (e) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = 'rgba(0, 0, 0, 0.04)';
    };

    const handleDragLeave = (e) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = '';
    };

    const handleDrop = (e, position) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = '';
        try {
            const photoData = JSON.parse(e.dataTransfer.getData('photo'));
            onPhotoAdd(position, photoData);
        } catch (error) {
            console.error('Error adding photo:', error);
        }
    };

    const { width, height } = getPageDimensions();

    // Создаем сетку 2x2 для размещения фотографий
    const gridSize = format.size === '20×20' ? '80px' : format.size === '30×30' ? '100px' : '120px';
    const iconSize = format.size === '20×20' ? 30 : format.size === '30×30' ? 40 : 50;

    const grid = Array(4).fill(null).map((_, index) => {
        const photo = photos.find(p => p.position === index);

        return (
            <Box
                key={index}
                sx={{
                    position: 'relative',
                    width: '100%',
                    height: '100%',
                    minHeight: gridSize,
                    border: '2px dashed',
                    borderColor: photo ? 'transparent' : 'grey.300',
                    borderRadius: 1,
                    overflow: 'hidden',
                    transition: 'all 0.2s ease-in-out',
                    '&:hover': {
                        borderColor: photo ? 'transparent' : 'primary.main',
                        backgroundColor: photo ? 'transparent' : 'action.hover',
                    },
                }}
                onDrop={(e) => handleDrop(e, index)}
                onDragOver={handleDragOver}
                onDragLeave={handleDragLeave}
            >
                {photo ? (
                    <img
                        src={photo.preview || photo.url}
                        alt={`Photo ${index}`}
                        style={{
                            width: '100%',
                            height: '100%',
                            objectFit: 'cover',
                        }}
                        onClick={() => onPhotoRemove(index)}
                    />
                ) : (
                    <Box
                        sx={{
                            width: '100%',
                            height: '100%',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            color: 'grey.500',
                        }}
                    >
                        <AddPhotoIcon sx={{ fontSize: iconSize }} />
                    </Box>
                )}
            </Box>
        );
    });

    return (
        <Box sx={{ mb: 4 }}>
            <Typography variant="h6" gutterBottom align="center">
                Страница 
            </Typography>
            <MotionPaper
                elevation={3}
                sx={{
                    width,
                    height,
                    margin: '0 auto',
                    position: 'relative',
                    backgroundColor: '#fff',
                    display: 'grid',
                    gridTemplateColumns: `repeat(2, 1fr)`,
                    gridTemplateRows: `repeat(2, 1fr)`,
                    gap: format.size === '20×20' ? 1 : 2,
                    p: format.size === '20×20' ? 1 : 2,
                    boxSizing: 'border-box',
                }}
            >
                {grid}
            </MotionPaper>
        </Box>
    );
};

export default PhotoBookPage;
